#include <bits/stdc++.h>
using namespace std;
int a[100005],b[100005];
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<=m;i++)cin>>b[i];
    //sort(a+1,a+n+1);
    sort(b+1,b+m+1);
    for(int i=1;i<=n;i++){
        int l=1,r=m;
        while(l<=m){
            int mid=(l+r)>>1;
            if(b[mid]==a[i]){
                cout<<b[mid]<<' ';
                break;
            }else if(b[mid-1]<a[i] && b[mid+1]>a[i])break;
            else if(b[mid]>a[i])r=mid-1;
            else{
                l=mid+1;
            }
        }
    }
    return 0;
}
